/* wms-report-icReceiptSearch-sql-oracle.xml - selectIcReceiptList */ #{GRIDPAGING_ROWNUMTYPE_TOP}
SELECT TO1.SUBUL_YYMM , TO1.CTKEY , T_CT.CTNAME , TO1.ICGRKEY , TO1.ICGRNAME , TO1.OWKEY , T_OW.OWNAME , TO1.ACKEY , TO1.ACNAME , TO1.ICKEY , TO1.ICNAME , T_IC.SPEC , TO1.CARRYOVER_QTY , TO1.CARRYOVER_COSTPRICE , TO1.ACIB_QTY /* 거래처 입고 수량 */ , TO1.ACIB_COSTPRICE /* 거래처 입고 금액 */ , TO1.ACOB_QTY /* 거래처 반출 수량 */ , TO1.ACOB_COSTPRICE /* 거래처 반출 금액 */ , TO1.OI_QTY /* 기타 입고 수량 */ , TO1.OI_COSTPRICE /* 기타 입고 금액 */ , TO1.IBTT_QTY /* 입고 수량 합계 */ , TO1.IBTT_COSTPRICE /* 입고 금액 합계 */ , TO1.STOB_QTY /* 점포 출고 수량 */ , TO1.STOB_COSTPRICE /* 점포 출고 금액 */ , TO1.STRI_QTY /* 점포 반입 수량 */ , TO1.STRI_COSTPRICE /* 점포 반입 금액 */ , TO1.STOBTT_QTY /* 점포 출고계 수량 */ , TO1.STOBTT_SALEPRICE /* 점포 출고계 매가 */ , TO1.STOBTT_COSTPRICE /* 점포 출고계 금액 */ , TO1.STOBTT_PROFIT /* 점포 출고계 이익 */ , TO1.DUOB_QTY /* 폐기 수량 */ , TO1.DUOB_COSTPRICE /* 폐기 금액 */ , TO1.DNOB_QTY /* 기부 수량 */ , TO1.DNOB_COSTPRICE /* 기부 금액 */ , TO1.DPOB_QTY /* 매각 수량 */ , TO1.DPOB_COSTPRICE /* 매각 금액 */ , TO1.OO_QTY /* 기타 출고 수량 */ , TO1.OO_COSTPRICE /* 기타 출고 금액 */ , TO1.SCO_QTY /* 자가 소비 수량 */ , TO1.SCO_COSTPRICE /* 자가 소비 금액 */ , TO1.IC_REPLACE_QTY /* 상품 대체 수량 */ , TO1.IC_REPLACE_COSTPRICE /*상품 대체 금액 */ , TO1.NER_OBTT_QTY /* 사내 대체 수량 */ , TO1.NER_OBTT_SALEPRICE /* 사내 대체 매가 */ , TO1.NER_OBTT_COSTPRICE /* 사내 대체 원가 */ , TO1.NER_OBTT_PROFIT /* 사내 대체 이익 */ , TO1.OBTT_QTY /* 출고 수량 합계 */ , TO1.OBTT_SALEPRICE /* 출고 매가 합계 */ , TO1.OBTT_COSTPRICE /* 출고 원가 합계 */ , TO1.OBTT_PROFIT /* 출고 합계 이익 */ , TO1.DIFF_TTQTY /* 상품 차이 수량 */ , TO1.DIFF_TTQTY_COSTPRICE /* 상품 차이 금액 */ , TO1.PRO_CAL_COSTPRICE /* 원가 정산 금액 */ , TO1.IV_CON_QTY /* 재고 반영 수량 */ , TO1.IV_CON_SALEPRICE /* 재고 반영 매가 */ , TO1.IV_CON_COSTPRICE /* 재고 반영 원가 */ , TO1.IV_CON_PROFIT /* 재고 반영 이익 */ , TO1.CLOSING_INVQTY , TO1.CLOSING_COSTPRICE , TO1.REP_ACKEY , TO1.REP_ACNAME , TO1.SUBUL_NAME , TO1.INSERTDATE , TO1.INSERTURKEY , TO1.UPDATEDATE , TO1.UPDATEURKEY , TO1.AVGCOSTPRICE , TO1.LOGGRPCD
ORDER BY TO1.SUBUL_YYMM , TO1.ICGRNAME , TO1.OWKEY , TO1.ICKEY , TO1.ICNAME #{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-report-icReceiptSearch-sql-oracle.xml - checkCloseYM */
SELECT COUNT(1)
  FROM TWORK_INFO_CLOSE_YM
 WHERE CLOSE_YM = #{closedt}
   AND CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND LOGGRPCD = #{loggrpcd}

/* wms-report-icReceiptSearch-sql-oracle.xml - checkProcessCnt */
SELECT COUNT(1)
  FROM TWORK_INFO_PROCESS_YM
 WHERE PROCESS_YM = #{closedt}
   AND CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND LOGGRPCD = #{loggrpcd}

