/* wms-report-icReceiptSearch-sql-oracle.xml - insertCheckProcess */
INSERT INTO TWORK_INFO_PROCESS_YM (
	   CTKEY
 	 , OWKEY
	 , LOGGRPCD
	 , PROCESS_YM
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
)
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{loggrpcd}
	 , #{closedt}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
)

/* wms-report-icReceiptSearch-sql-oracle.xml - deleteCheckProcess */
DELETE
  FROM TWORK_INFO_PROCESS_YM
 WHERE PROCESS_YM = #{closedt}
   AND CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND LOGGRPCD = #{loggrpcd}

mapper.delete:
/* wms-report-icReceiptSearch-sql-oracle.xml - deleteIcReceiptClose */
DELETE
  FROM TWORK_INFO_IVST1
 WHERE CLOSING_DATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959'
   AND CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND LOGGRPCD = #{loggrpcd}

mapper.insert:
/* wms-report-icReceiptSearch-sql-oracle.xml - insertIcReceiptClose */ INSERT INTO TWORK_INFO_IVST1 ( CLOSING_TYPE /* 마감 유형 */ , CLOSING_DATE /* 마감 일자 */ , CTKEY /* 센터 코드 */ , OWKEY /* 화주 코드 */ , ICKEY /* 물품 코드 */ , LOGGRPCD /* 상저온 코드 */ , ICGRKEY /* 상품 그룹 코드 */ , STORE_KEY /* 점포 코드 */ , CARRYOVER_QTY /* 전일 재고 */ , CARRYOVER_COSTPRICE /* 전일 재고 원가 */ , CARRYOVER_SALEPRICE /* 전일 재고 총 판매가 */ , CLOSING_INVQTY /* 마감 재고 수량 */ , CLOSING_COSTPRICE /* 마감 재고 원가 */ , CLOSING_SALEPRICE /* 마감 재고 판매가 */ , ORHDTYPE /* 주문 공통 유형 */ , TTQTY /* 총 수량 */ , TTQTY_COSTPRICE /* 총 주문 원가 */ , TTQTY_SALEPRICE /* 총 주문 판매가 */ , TTIBCANCELQTY /* 총 입고 취소 수량 */ , TTADJQTY /* 총 조정 수량 */ , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY , DCKEY , CHITYMD , SUBULYMD , ICGRTYPE , TRUNC_COSTPRICE , DIFF_TTQTY , DIFF_TTQTY_COSTPRICE ) /* 입고 집계 */ SELECT 'IB' , #{subulymd} || '000000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.LOGGRPCD , TO1.ICGRKEY , COALESCE(TO1.STORE_KEY, ' ') , 0 , 0 , 0 , 0 , 0 , 0 , TO1.IBHDTYPE , TO1.CFQTY , TO1.COSTPRICE , COALESCE(TO1.SALEPRICE, 0) , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , TO1.DCKEY , TO1.CHITYMD , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.IBHDTYPE , SUM(T1.CFQTY) AS CFQTY , TRUNC(SUM(T1.COSTPRICE)) AS COSTPRICE , TRUNC(SUM(T1.SALEPRICE)) AS SALEPRICE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE FROM ( SELECT B.CTKEY , B.OWKEY , C.ICKEY , C.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END AS CFQTY , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END * C.COSTPRICE AS COSTPRICE , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END * C.SALEPRICE AS SALEPRICE , B.DCKEY , C.CHITYMD , C.ICGRTYPE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE NOT IN ('50', '90') AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959'
UNION ALL
SELECT B.CTKEY , B.OWKEY , C.ICKEY , B.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END AS CFQTY , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END * C.COSTPRICE AS COSTPRICE , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END * C.SALEPRICE AS SALEPRICE , B.DCKEY , C.ORGCHITYMD , C.ICGRTYPE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE = '50' AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.IBHDTYPE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE ) TO1 UNION ALL
/* 공병 공박스 집계 */ SELECT 'IB' , #{subulymd} || '000000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.LOGGRPCD , TO1.ICGRKEY , COALESCE(TO1.STORE_KEY, ' ') , 0 , 0 , 0 , 0 , 0 , 0 , TO1.IBHDTYPE , SUM(TO1.CFQTY) , SUM(TO1.COSTPRICE) , SUM(TO1.SALEPRICE) , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , TO1.DCKEY , TO1.CHITYMD , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT B.CTKEY , B.OWKEY , H.BOTTLE_ICKEY AS ICKEY , B.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , COALESCE((CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END + CASE WHEN H.CNTRTYPE = '1' THEN 0 ELSE COALESCE(C.BO_QTY, 0) END) / H.ICUTQTY, 0) AS CFQTY , COALESCE((CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END + CASE WHEN H.CNTRTYPE = '1' THEN 0 ELSE COALESCE(C.BO_QTY, 0) END) / H.ICUTQTY, 0) * COALESCE(H.COSTPRICE, 0) AS COSTPRICE , COALESCE((CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END + CASE WHEN H.CNTRTYPE = '1' THEN 0 ELSE COALESCE(C.BO_QTY, 0) END) / H.ICUTQTY, 0) * COALESCE(H.SALEPRICE, 0) AS SALEPRICE , B.DCKEY , C.CHITYMD , C.ICGRTYPE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY INNER JOIN ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.BOTTLE_ICKEY , T1.ICUTQTY , T1.COSTPRICE , T2.SALEPRICE , T1.CNTRTYPE , T2.ACKEY FROM ( SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , 1 AS ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '2' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOTTLEPRICE WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N'
UNION ALL
SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , C.ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '1' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOXPRICE INNER JOIN TWORK_MST_ICUTXTYPE C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICUTKEY = C.ICUTKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N' AND C.ICUTTYPE = 'IP' ) T1 INNER JOIN TWORK_MST_IC T2 ON T1.CTKEY = T2.CTKEY AND T1.OWKEY = T2.OWKEY AND T1.BOTTLE_ICKEY = T2.ICKEY WHERE T2.CTKEY = #{ctkey} AND T2.OWKEY = #{owkey} ) H ON C.CTKEY = H.CTKEY AND C.OWKEY = H.OWKEY AND C.ICKEY = H.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.LOGGRPCD = #{loggrpcd} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE NOT IN ('50', '90', '160') AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) TO1 GROUP BY TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , TO1.IBHDTYPE , TO1.DCKEY , TO1.CHITYMD , TO1.ICGRTYPE
UNION ALL
SELECT 'IB' , #{subulymd} || '000000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.LOGGRPCD , TO1.ICGRKEY , COALESCE(TO1.STORE_KEY, ' ') , 0 , 0 , 0 , 0 , 0 , 0 , TO1.IBHDTYPE , SUM(TO1.CFQTY) , SUM(TO1.COSTPRICE) , SUM(TO1.SALEPRICE) , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , TO1.DCKEY , TO1.CHITYMD , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT B.CTKEY , B.OWKEY , H.BOTTLE_ICKEY AS ICKEY , B.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) AS CFQTY , (COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) * COALESCE(H.COSTPRICE, 0)) AS COSTPRICE , (COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) * COALESCE(H.SALEPRICE, 0)) AS SALEPRICE , B.DCKEY , C.CHITYMD , C.ICGRTYPE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY INNER JOIN ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.BOTTLE_ICKEY , T1.ICUTQTY , T1.COSTPRICE , T2.SALEPRICE , T1.CNTRTYPE , T2.ACKEY FROM ( SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , 1 AS ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '2' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOTTLEPRICE WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N'
UNION ALL
SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , C.ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '1' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOXPRICE INNER JOIN TWORK_MST_ICUTXTYPE C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICUTKEY = C.ICUTKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N' AND C.ICUTTYPE = 'CS' ) T1 INNER JOIN TWORK_MST_IC T2 ON T1.CTKEY = T2.CTKEY AND T1.OWKEY = T2.OWKEY AND T1.BOTTLE_ICKEY = T2.ICKEY WHERE T2.CTKEY = #{ctkey} AND T2.OWKEY = #{owkey} ) H ON C.CTKEY = H.CTKEY AND C.OWKEY = H.OWKEY AND C.ICKEY = H.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE = '50' AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) TO1 GROUP BY TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , TO1.IBHDTYPE , TO1.DCKEY , TO1.CHITYMD , TO1.ICGRTYPE
UNION ALL
/* 파렛트 집계 */ SELECT 'IB' , #{subulymd} || '000000' , B.CTKEY , B.OWKEY , D.ICKEY , B.LOGGRPCD , D.ICGRKEY , COALESCE(B.STORE_KEY, ' ') , 0 , 0 , 0 , 0 , 0 , 0 , B.IBHDTYPE , COALESCE(SUM(B.PLQTY), 0) AS CFQTY , SUM(TRUNC(COALESCE(B.PLQTY, 0) * D.COSTPRICE)) AS COSTPRICE , SUM(TRUNC(COALESCE(B.PLQTY, 0) * D.SALEPRICE)) AS SALEPRICE , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , B.DCKEY , '' , #{subulymd} , D.ICGRTYPE , 0 , 0 , 0 FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_MST_IC D ON B.CTKEY = D.CTKEY AND B.OWKEY = D.OWKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE != '90' AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' AND D.ICKEY = '0000009999999' AND B.PLQTY > 0 GROUP BY B.CTKEY , B.OWKEY , D.ICKEY , B.LOGGRPCD , D.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , B.DCKEY , D.ICGRTYPE
UNION ALL
/* 출고 집계 */ SELECT 'OB' , #{subulymd} || '000000' , T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.LOGGRPCD , T1.ICGRKEY , COALESCE(T1.STORE_KEY, ' ') , 0 , 0 , 0 , 0 , 0 , 0 , T1.OBHDTYPE , SUM(T1.CFQTY) AS CFQTY , SUM(T1.COSTPRICE) AS COSTPRICE , SUM(T1.SALEPRICE) AS SALEPRICE , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , T1.DCKEY , T1.CHITYMD , #{subulymd} , T1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT A.CTKEY , A.OWKEY , B.ICKEY , B.LOGGRPCD , B.ICGRKEY , A.OBHDTYPE , COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) AS CFQTY , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) * COALESCE(B.COSTPRICE, 0)) AS COSTPRICE , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) * COALESCE(B.SALEPRICE, 0)) AS SALEPRICE , A.DCKEY , B.CHITYMD , B.ICGRTYPE , A.STORE_KEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND B.LOGGRPCD = #{loggrpcd} AND B.WKSTATUS BETWEEN '81' AND '90' AND C.VOLTYPE NOT IN ('10', '11') AND A.OBHDTYPE IN ('10', '20', '200') AND A.OBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' AND B.CHITYMD IS NOT NULL ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.OBHDTYPE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE
UNION ALL
/* 출고 집계 */ SELECT 'OB' , #{subulymd} || '000000' , T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.LOGGRPCD , T1.ICGRKEY , COALESCE(T1.STORE_KEY, ' ') , 0 , 0 , 0 , 0 , 0 , 0 , T1.OBHDTYPE , SUM(T1.CFQTY) AS CFQTY , SUM(T1.COSTPRICE) AS COSTPRICE , SUM(T1.SALEPRICE) AS SALEPRICE , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , T1.DCKEY , T1.CHITYMD , #{subulymd} , T1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT A.CTKEY , A.OWKEY , B.ICKEY , B.LOGGRPCD , B.ICGRKEY , A.OBHDTYPE , COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) AS CFQTY , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) * COALESCE(B.COSTPRICE, 0)) AS COSTPRICE , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) * COALESCE(B.SALEPRICE, 0)) AS SALEPRICE , B.DCKEY , B.CHITYMD , B.ICGRTYPE , A.STORE_KEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND B.WKSTATUS BETWEEN '81' AND '90' AND C.VOLTYPE NOT IN ('10', '11') AND A.OBHDTYPE NOT IN ('10', '20', '200') AND A.OBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.OBHDTYPE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE
UNION ALL
/* 출고 집계 CHIT_YMD NULL */ SELECT 'OB' , #{subulymd} || '000000' , T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.LOGGRPCD , T1.ICGRKEY , COALESCE(T1.STORE_KEY, ' ') , 0 , 0 , 0 , 0 , 0 , 0 , T1.OBHDTYPE , SUM(T1.CFQTY) AS CFQTY , SUM(T1.COSTPRICE) AS COSTPRICE , SUM(T1.SALEPRICE) AS SALEPRICE , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , T1.DCKEY , T1.CHITYMD , #{subulymd} , T1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT A.CTKEY , A.OWKEY , B.ICKEY , B.LOGGRPCD , B.ICGRKEY , A.OBHDTYPE , COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) AS CFQTY , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) * COALESCE(B.COSTPRICE, 0)) AS COSTPRICE , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN B.CFQTY*-1 ELSE B.CFQTY END, 0) * COALESCE(B.SALEPRICE, 0)) AS SALEPRICE , A.DCKEY , B.CHITYMD , B.ICGRTYPE , A.STORE_KEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND B.WKSTATUS BETWEEN '81' AND '90' AND C.VOLTYPE NOT IN ('10', '11') AND A.OBHDTYPE IN ('10', '20', '200') AND A.OBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' AND B.CHITYMD IS NULL ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.OBHDTYPE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE
UNION ALL
/* 공병 공박스(출고) */ SELECT 'OB' , #{subulymd} || '000000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.LOGGRPCD , TO1.ICGRKEY , COALESCE(TO1.STORE_KEY, ' ') , 0 , 0 , 0 , 0 , 0 , 0 , TO1.OBHDTYPE , SUM(TO1.CFQTY) , SUM(TO1.COSTPRICE) , SUM(TO1.SALEPRICE) , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , TO1.DCKEY , TO1.CHITYMD , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT B.CTKEY , B.OWKEY , H.BOTTLE_ICKEY AS ICKEY , B.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.OBHDTYPE , COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) AS CFQTY , COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) * COALESCE(H.COSTPRICE, 0) AS COSTPRICE , COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) * COALESCE(H.SALEPRICE, 0) AS SALEPRICE , B.DCKEY , C.CHITYMD , C.ICGRTYPE FROM TWORK_INFO_OB_HD B INNER JOIN TWORK_INFO_OB_DT C ON B.OBHDKEY = C.OBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY INNER JOIN ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.BOTTLE_ICKEY , T1.ICUTQTY , T1.COSTPRICE , T2.SALEPRICE , T1.CNTRTYPE , T2.ACKEY FROM ( SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , 1 AS ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '2' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOTTLEPRICE WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N'
UNION ALL
SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , C.ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '1' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOXPRICE INNER JOIN TWORK_MST_ICUTXTYPE C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICUTKEY = C.ICUTKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N' AND C.ICUTTYPE = 'CS' ) T1 INNER JOIN TWORK_MST_IC T2 ON T1.CTKEY = T2.CTKEY AND T1.OWKEY = T2.OWKEY AND T1.BOTTLE_ICKEY = T2.ICKEY WHERE T2.CTKEY = #{ctkey} AND T2.OWKEY = #{owkey} ) H ON C.CTKEY = H.CTKEY AND C.OWKEY = H.OWKEY AND C.ICKEY = H.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.WKSTATUS BETWEEN '81' AND '90' AND B.OBHDTYPE IN ('40', '90', '180', '80') AND D.VOLTYPE NOT IN ('10', '11') AND B.OBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) TO1 GROUP BY TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , TO1.OBHDTYPE , TO1.DCKEY , TO1.CHITYMD , TO1.ICGRTYPE

