/* wms-report-icReceiptSearch-sql-oracle.xml - insertIcReceiptClose2 */ INSERT INTO TWORK_INFO_IVST3 ( CLOSING_TYPE /* 마감 유형 */ , CLOSING_DATE /* 마감 일자 */ , CTKEY /* 센터 코드 */ , OWKEY /* 화주 코드 */ , ICKEY /* 물품 코드 */ , IVATKEY /* 재고 속성 코드 */ , LOGGRPCD /* 상저온 코드 */ , ICGRKEY /* 상품 그룹 코드 */ , STORE_KEY /* 점포 코드 */ , CARRYOVER_QTY /* 전일 재고 */ , CARRYOVER_COSTPRICE /* 전일 재고 원가 */ , CARRYOVER_SALEPRICE /* 전일 재고 총 판매가 */ , CLOSING_INVQTY /* 마감 재고 수량 */ , CLOSING_COSTPRICE /* 마감 재고 원가 */ , CLOSING_SALEPRICE /* 마감 재고 판매가 */ , ORHDTYPE /* 주문 공통 유형 */ , TTQTY /* 총 수량 */ , TTQTY_COSTPRICE /* 총 주문 원가 */ , TTQTY_SALEPRICE /* 총 주문 판매가 */ , TTIBCANCELQTY /* 총 입고 취소 수량 */ , TTADJQTY /* 총 조정 수량 */ , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY , DCKEY , CHITYMD , SUBULYMD , ICGRTYPE , TRUNC_COSTPRICE , DIFF_TTQTY , DIFF_TTQTY_COSTPRICE )
/* 입고 집계 */ SELECT 'IB' , #{subulymd} || '000000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.IVATKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , 0 , 0 , 0 , 0 , 0 , 0 , TO1.IBHDTYPE , TO1.CFQTY , TO1.COSTPRICE , COALESCE(TO1.SALEPRICE, 0) , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , TO1.DCKEY , TO1.CHITYMD , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.IBHDTYPE , SUM(T1.CFQTY) AS CFQTY , TRUNC(SUM(T1.COSTPRICE)) AS COSTPRICE , TRUNC(SUM(T1.SALEPRICE)) AS SALEPRICE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE FROM ( SELECT B.CTKEY , B.OWKEY , C.ICKEY , C.TO_IVATKEY AS IVATKEY , C.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END AS CFQTY , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END * C.COSTPRICE AS COSTPRICE , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END * C.SALEPRICE AS SALEPRICE , B.DCKEY , C.CHITYMD , C.ICGRTYPE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE NOT IN ('50', '90') AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959'
UNION ALL
SELECT B.CTKEY , B.OWKEY , C.ICKEY , C.TO_IVATKEY AS IVATKEY , B.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END AS CFQTY , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END * C.COSTPRICE AS COSTPRICE , CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END * C.SALEPRICE AS SALEPRICE , B.DCKEY , C.ORGCHITYMD , C.ICGRTYPE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE = '50' AND B.IBCONFIRMDATE BETWEEN #{subulymd}|| '000000' AND #{subulymd} || '235959' ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.IBHDTYPE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE ) TO1
UNION ALL
/* 공병 공박스 집계 */ SELECT 'IB' , #{subulymd} || '000000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.IVATKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , 0 , 0 , 0 , 0 , 0 , 0 , TO1.IBHDTYPE , SUM(TO1.CFQTY) , SUM(TO1.COSTPRICE) , SUM(TO1.SALEPRICE) , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , TO1.DCKEY , TO1.CHITYMD , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT B.CTKEY , B.OWKEY , H.BOTTLE_ICKEY AS ICKEY , C.TO_IVATKEY AS IVATKEY , B.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , COALESCE((CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END + CASE WHEN H.CNTRTYPE = '1' THEN 0 ELSE COALESCE(C.BO_QTY, 0) END) / H.ICUTQTY, 0) AS CFQTY , COALESCE((CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END + CASE WHEN H.CNTRTYPE = '1' THEN 0 ELSE COALESCE(C.BO_QTY, 0) END) / H.ICUTQTY, 0) * COALESCE(H.COSTPRICE, 0) AS COSTPRICE , COALESCE((CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END + CASE WHEN H.CNTRTYPE = '1' THEN 0 ELSE COALESCE(C.BO_QTY, 0) END) / H.ICUTQTY, 0) * COALESCE(H.SALEPRICE, 0) AS SALEPRICE , B.DCKEY , C.CHITYMD , C.ICGRTYPE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY INNER JOIN ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.BOTTLE_ICKEY , T1.ICUTQTY , T1.COSTPRICE , T2.SALEPRICE , T1.CNTRTYPE , T2.ACKEY FROM ( SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , 1 AS ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '2' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOTTLEPRICE WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N'
UNION ALL
SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , C.ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '1' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOXPRICE INNER JOIN TWORK_MST_ICUTXTYPE C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICUTKEY = C.ICUTKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N' AND C.ICUTTYPE = 'IP' ) T1 INNER JOIN TWORK_MST_IC T2 ON T1.CTKEY = T2.CTKEY AND T1.OWKEY = T2.OWKEY AND T1.BOTTLE_ICKEY = T2.ICKEY WHERE T2.CTKEY = #{ctkey} AND T2.OWKEY = #{owkey}
) H ON C.CTKEY = H.CTKEY AND C.OWKEY = H.OWKEY AND C.ICKEY = H.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE NOT IN ('50', '90', '160') AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) TO1 GROUP BY TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.IVATKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , TO1.IBHDTYPE , TO1.DCKEY , TO1.CHITYMD , TO1.ICGRTYPE
UNION ALL
SELECT 'IB' , #{subulymd} || '000000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.IVATKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , 0 , 0 , 0 , 0 , 0 , 0 , TO1.IBHDTYPE , SUM(TO1.CFQTY) , SUM(TO1.COSTPRICE) , SUM(TO1.SALEPRICE) , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , TO1.DCKEY , TO1.CHITYMD , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT B.CTKEY , B.OWKEY , H.BOTTLE_ICKEY AS ICKEY , C.TO_IVATKEY AS IVATKEY , B.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) AS CFQTY , (COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) * COALESCE(H.COSTPRICE, 0)) AS COSTPRICE , (COALESCE(CASE C.UDF4 WHEN '-1' THEN C.CFQTY*-1 ELSE C.CFQTY END / H.ICUTQTY, 0) * COALESCE(H.SALEPRICE, 0)) AS SALEPRICE , B.DCKEY , C.CHITYMD , C.ICGRTYPE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY INNER JOIN ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.BOTTLE_ICKEY , T1.ICUTQTY , T1.COSTPRICE , T2.SALEPRICE , T1.CNTRTYPE , T2.ACKEY FROM ( SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , 1 AS ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '2' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOTTLEPRICE WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N'
UNION ALL
SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , C.ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '1' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOXPRICE INNER JOIN TWORK_MST_ICUTXTYPE C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICUTKEY = C.ICUTKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N' AND C.ICUTTYPE = 'CS' ) T1 INNER JOIN TWORK_MST_IC T2 ON T1.CTKEY = T2.CTKEY AND T1.OWKEY = T2.OWKEY AND T1.BOTTLE_ICKEY = T2.ICKEY WHERE T2.CTKEY = #{ctkey} AND T2.OWKEY = #{owkey} ) H ON C.CTKEY = H.CTKEY AND C.OWKEY = H.OWKEY AND C.ICKEY = H.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE = '50' AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) TO1 GROUP BY TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.IVATKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , TO1.IBHDTYPE , TO1.DCKEY , TO1.CHITYMD , TO1.ICGRTYPE
UNION ALL
/* 파렛트 집계 */ SELECT 'IB' , #{subulymd} || '000000' , B.CTKEY , B.OWKEY , D.ICKEY , C.TO_IVATKEY , B.LOGGRPCD , D.ICGRKEY , B.STORE_KEY , 0 , 0 , 0 , 0 , 0 , 0 , B.IBHDTYPE , COALESCE(SUM(B.PLQTY), 0) AS CFQTY , SUM(TRUNC(COALESCE(B.PLQTY, 0) * D.COSTPRICE)) AS COSTPRICE , SUM(TRUNC(COALESCE(B.PLQTY, 0) * D.SALEPRICE)) AS SALEPRICE , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , B.DCKEY , '' , #{subulymd} , D.ICGRTYPE , 0 , 0 , 0 FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.IBHDKEY = C.IBHDKEY INNER JOIN TWORK_MST_IC D ON B.CTKEY = D.CTKEY AND B.OWKEY = D.OWKEY AND C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND D.VOLTYPE NOT IN ('10', '11') AND B.IBHDTYPE != '90' AND B.IBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' AND D.ICKEY = '0000009999999' AND B.PLQTY > 0 GROUP BY B.CTKEY , B.OWKEY , D.ICKEY , C.TO_IVATKEY , B.LOGGRPCD , D.ICGRKEY , B.STORE_KEY , B.IBHDTYPE , B.DCKEY , D.ICGRTYPE
UNION ALL
/* 출고 집계 */ SELECT 'OB' , #{subulymd} || '000000' , T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , 0 , 0 , 0 , 0 , 0 , 0 , T1.OBHDTYPE , SUM(T1.CFQTY) AS CFQTY , SUM(T1.COSTPRICE) AS COSTPRICE , SUM(T1.SALEPRICE) AS SALEPRICE , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , T1.DCKEY , T1.CHITYMD , #{subulymd} , T1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT A.CTKEY , A.OWKEY , B.ICKEY , D.IVATKEY , B.LOGGRPCD , B.ICGRKEY , A.OBHDTYPE , COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) AS CFQTY , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) * COALESCE(B.COSTPRICE, 0)) AS COSTPRICE , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) * COALESCE(B.SALEPRICE, 0)) AS SALEPRICE , A.DCKEY , B.CHITYMD , B.ICGRTYPE , A.STORE_KEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY INNER JOIN TWORK_INFO_PI_DT D ON B.CTKEY = D.CTKEY AND B.OWKEY = D.OWKEY AND B.ICKEY = D.ICKEY AND B.OBHDKEY = D.OBHDKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND B.WKSTATUS BETWEEN '81' AND '90' AND C.VOLTYPE NOT IN ('10', '11') AND A.OBHDTYPE IN ('10', '20', '200') AND A.OBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' AND B.CHITYMD IS NOT NULL ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.OBHDTYPE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE
UNION ALL
/* 출고 집계 */ SELECT 'OB' , #{subulymd} || '000000' , T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , 0 , 0 , 0 , 0 , 0 , 0 , T1.OBHDTYPE , SUM(T1.CFQTY) AS CFQTY , SUM(T1.COSTPRICE) AS COSTPRICE , SUM(T1.SALEPRICE) AS SALEPRICE , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , T1.DCKEY , T1.CHITYMD , #{subulymd} , T1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT A.CTKEY , A.OWKEY , B.ICKEY , D.IVATKEY , B.LOGGRPCD , B.ICGRKEY , A.OBHDTYPE , COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) AS CFQTY , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) * COALESCE(B.COSTPRICE, 0)) AS COSTPRICE , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) * COALESCE(B.SALEPRICE, 0)) AS SALEPRICE , B.DCKEY , B.CHITYMD , B.ICGRTYPE , A.STORE_KEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY INNER JOIN TWORK_INFO_PI_DT D ON B.CTKEY = D.CTKEY AND B.OWKEY = D.OWKEY AND B.ICKEY = D.ICKEY AND B.OBHDKEY = D.OBHDKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND B.WKSTATUS BETWEEN '81' AND '90' AND C.VOLTYPE NOT IN ('10', '11') AND A.OBHDTYPE NOT IN ('10', '20', '200') AND A.OBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.OBHDTYPE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE
UNION ALL
/* 출고 집계 CHIT_YMD NULL */ SELECT 'OB' , #{subulymd} || '000000' , T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , 0 , 0 , 0 , 0 , 0 , 0 , T1.OBHDTYPE , SUM(T1.CFQTY) AS CFQTY , SUM(T1.COSTPRICE) AS COSTPRICE , SUM(T1.SALEPRICE) AS SALEPRICE , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , T1.DCKEY , T1.CHITYMD , #{subulymd} , T1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT A.CTKEY , A.OWKEY , B.ICKEY , D.IVATKEY , B.LOGGRPCD , B.ICGRKEY , A.OBHDTYPE , COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) AS CFQTY , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) * COALESCE(B.COSTPRICE, 0)) AS COSTPRICE , TRUNC(COALESCE(CASE B.UDF4 WHEN '-1' THEN D.CFQTY*-1 ELSE D.CFQTY END, 0) * COALESCE(B.SALEPRICE, 0)) AS SALEPRICE , A.DCKEY , B.CHITYMD , B.ICGRTYPE , A.STORE_KEY FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.OBHDKEY = B.OBHDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY INNER JOIN TWORK_INFO_PI_DT D ON B.CTKEY = D.CTKEY AND B.OWKEY = D.OWKEY AND B.ICKEY = D.ICKEY AND B.OBHDKEY = D.OBHDKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND B.WKSTATUS BETWEEN '81' AND '90' AND C.VOLTYPE NOT IN ('10', '11') AND A.OBHDTYPE IN ('10', '20', '200') AND A.OBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' AND B.CHITYMD IS NULL ) T1 GROUP BY T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.IVATKEY , T1.LOGGRPCD , T1.ICGRKEY , T1.STORE_KEY , T1.OBHDTYPE , T1.DCKEY , T1.CHITYMD , T1.ICGRTYPE
UNION ALL
/* 공병 공박스(출고) */ SELECT 'OB' , #{subulymd} || '000000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.IVATKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , 0 , 0 , 0 , 0 , 0 , 0 , TO1.OBHDTYPE , SUM(TO1.CFQTY) , SUM(TO1.COSTPRICE) , SUM(TO1.SALEPRICE) , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , TO1.DCKEY , TO1.CHITYMD , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT B.CTKEY , B.OWKEY , H.BOTTLE_ICKEY AS ICKEY , E.IVATKEY , B.LOGGRPCD , C.ICGRKEY , B.STORE_KEY , B.OBHDTYPE , COALESCE(CASE C.UDF4 WHEN '-1' THEN E.CFQTY*-1 ELSE E.CFQTY END / H.ICUTQTY, 0) AS CFQTY , COALESCE(CASE C.UDF4 WHEN '-1' THEN E.CFQTY*-1 ELSE E.CFQTY END / H.ICUTQTY, 0) * COALESCE(H.COSTPRICE, 0) AS COSTPRICE , COALESCE(CASE C.UDF4 WHEN '-1' THEN E.CFQTY*-1 ELSE E.CFQTY END / H.ICUTQTY, 0) * COALESCE(H.SALEPRICE, 0) AS SALEPRICE , B.DCKEY , C.CHITYMD , C.ICGRTYPE FROM TWORK_INFO_OB_HD B INNER JOIN TWORK_INFO_OB_DT C ON B.CTKEY = C.CTKEY AND B.OBHDKEY = C.OBHDKEY INNER JOIN TWORK_MST_IC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY INNER JOIN TWORK_INFO_PI_DT E ON C.CTKEY = E.CTKEY AND C.OWKEY = E.OWKEY AND C.ICKEY = E.ICKEY AND C.OBHDKEY = E.OBHDKEY INNER JOIN ( SELECT T1.CTKEY , T1.OWKEY , T1.ICKEY , T1.BOTTLE_ICKEY , T1.ICUTQTY , T1.COSTPRICE , T2.SALEPRICE , T1.CNTRTYPE , T2.ACKEY FROM ( SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , 1 AS ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '2' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOTTLEPRICE WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N'
UNION ALL
SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.BOTTLE_ICKEY , C.ICUTQTY , A.CNTRPRICE AS COSTPRICE , B.SALEPRICE , A.CNTRTYPE FROM ( SELECT CTKEY , CNTRKEY , OWKEY , CNTRPRICE , ICKEY AS BOTTLE_ICKEY , CNTRTYPE FROM TWORK_MST_CNTR WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND CNTRTYPE = '1' ) A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.CNTRPRICE = B.BOXPRICE INNER JOIN TWORK_MST_ICUTXTYPE C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICUTKEY = C.ICUTKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.ICGRKEY = '02' AND B.DELYN = 'N' AND C.ICUTTYPE = 'CS' ) T1 INNER JOIN TWORK_MST_IC T2 ON T1.CTKEY = T2.CTKEY AND T1.OWKEY = T2.OWKEY AND T1.BOTTLE_ICKEY = T2.ICKEY WHERE T2.CTKEY = #{ctkey} AND T2.OWKEY = #{owkey} ) H ON C.CTKEY = H.CTKEY AND C.OWKEY = H.OWKEY AND C.ICKEY = H.ICKEY WHERE B.CTKEY = #{ctkey} AND B.OWKEY = #{owkey} AND B.WKSTATUS BETWEEN '81' AND '90' AND B.OBHDTYPE IN ('40', '90', '180', '80') AND D.VOLTYPE NOT IN ('10', '11') AND B.OBCONFIRMDATE BETWEEN #{subulymd} || '000000' AND #{subulymd} || '235959' ) TO1 GROUP BY TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.IVATKEY , TO1.LOGGRPCD , TO1.ICGRKEY , TO1.STORE_KEY , TO1.OBHDTYPE , TO1.DCKEY , TO1.CHITYMD , TO1.ICGRTYPE

/* wms-report-icReceiptSearch-sql-oracle.xml - insertIcSetReceiptIvClose */ INSERT INTO TWORK_INFO_IVST1 ( CLOSING_TYPE /* 마감 유형 */ , CLOSING_DATE /* 마감 일자 */ , CTKEY /* 센터 코드 */ , OWKEY /* 화주 코드 */ , ICKEY /* 물품 코드 */ , LOGGRPCD /* 상저온 코드 */ , ICGRKEY /* 상품 그룹 코드 */ , STORE_KEY /* 점포 코드 */ , CARRYOVER_QTY /* 전일 재고 */ , CARRYOVER_COSTPRICE /* 전일 재고 원가 */ , CARRYOVER_SALEPRICE /* 전일 재고 총 판매가 */ , CLOSING_INVQTY /* 마감 재고 수량 */ , CLOSING_COSTPRICE /* 마감 재고 원가 */ , CLOSING_SALEPRICE /* 마감 재고 판매가 */ , ORHDTYPE /* 주문 공통 유형 */ , TTQTY /* 총 주문 원가 */ , TTQTY_COSTPRICE /* 총 주문 판매가 */ , TTQTY_SALEPRICE /* 총 입고 취소 수량 */ , TTIBCANCELQTY /* 총 조정 수량 */ , TTADJQTY , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY , DCKEY , CHITYMD , SUBULYMD , ICGRTYPE , TRUNC_COSTPRICE , DIFF_TTQTY , DIFF_TTQTY_COSTPRICE ) SELECT 'IV' , TO_CHAR(TO_DATE(#{subulymd}, 'YYYYMMDD') - 1, 'YYYYMMDD') || '150000' , TO1.CTKEY , TO1.OWKEY , TO1.ICKEY , TO1.LOGGRPCD , TO1.ICGRKEY , '' , 0 , 0 , 0 , COALESCE(TO1.CFQTY, 0) , COALESCE(TO1.COSTPRICE, 0) , COALESCE(TO1.SALEPRICE, 0) , TO1.SP_HDTYPE , 0 , 0 , 0 , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , '' , '' , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT A.CTKEY , A.OWKEY , A.ICKEY , A.LOGGRPCD , A.ICGRKEY , A.SP_HDTYPE , SUM(COALESCE(CASE SP_HDTYPE WHEN '018' THEN A.CFQTY ELSE A.CFQTY * (-1) END, 0)) AS CFQTY , SUM(TRUNC(COALESCE(CASE SP_HDTYPE WHEN '018' THEN A.CFQTY * A.COSTPRICE ELSE (A.CFQTY * A.COSTPRICE) * (-1) END, 0))) AS COSTPRICE , SUM(TRUNC(COALESCE(CASE SP_HDTYPE WHEN '018' THEN A.CFQTY * A.SALEPRICE ELSE (A.CFQTY * A.SALEPRICE) * (-1) END, 0))) AS SALEPRICE , A.ICGRTYPE FROM TWORK_INFO_SP_HD A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND A.WKSTATUS = '90' AND A.LOGGRPCD = #{loggrpcd} AND A.SPCONFIRMDATE BETWEEN TO_CHAR(TO_DATE(#{subulymd}, 'YYYYMMDD') - 1, 'YYYYMMDD') || '150000' AND #{subulymd} || '145959' GROUP BY A.CTKEY , A.OWKEY , A.ICKEY , A.LOGGRPCD , A.ICGRKEY , A.SP_HDTYPE , A.ICGRTYPE
UNION ALL
SELECT B.CTKEY , B.OWKEY , B.ICKEY , A.LOGGRPCD , B.ICGRKEY , A.SP_HDTYPE , SUM(COALESCE(CASE SP_HDTYPE WHEN '019' THEN B.CFQTY ELSE B.CFQTY * (-1) END, 0)) AS CFQTY , SUM(COALESCE(CASE SP_HDTYPE WHEN '019' THEN B.CFQTY * B.COSTPRICE ELSE (B.CFQTY * B.COSTPRICE) * (-1) END, 0)) AS COSTPRICE , SUM(COALESCE(CASE SP_HDTYPE WHEN '019' THEN B.CFQTY * B.SALEPRICE ELSE (B.CFQTY * B.SALEPRICE) * (-1) END, 0)) AS SALEPRICE , B.ICGRTYPE FROM TWORK_INFO_SP_HD A INNER JOIN TWORK_INFO_SP_DT B ON A.CTKEY = B.CTKEY AND A.SP_HDKEY = B.SP_HDKEY INNER JOIN TWORK_MST_IC C ON B.CTKEY = C.CTKEY AND B.OWKEY = C.OWKEY AND B.ICKEY = C.ICKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND A.WKSTATUS = '90' AND A.LOGGRPCD = #{loggrpcd} AND A.SPCONFIRMDATE BETWEEN TO_CHAR(TO_DATE(#{subulymd}, 'YYYYMMDD') - 1, 'YYYYMMDD') || '150000' AND #{subulymd} || '145959' GROUP BY B.CTKEY , B.OWKEY , B.ICKEY , A.LOGGRPCD , B.ICGRKEY , A.SP_HDTYPE , B.ICGRTYPE ) TO1

/* wms-report-icReceiptSearch-sql-oracle.xml - insertIvReceiptIvClose */ INSERT INTO TWORK_INFO_IVST1 ( CLOSING_TYPE , CLOSING_DATE , CTKEY , OWKEY , ICKEY , LOGGRPCD , ICGRKEY , STORE_KEY , CARRYOVER_QTY , CARRYOVER_COSTPRICE , CARRYOVER_SALEPRICE , CLOSING_INVQTY , CLOSING_COSTPRICE , CLOSING_SALEPRICE , ORHDTYPE , TTQTY , TTQTY_COSTPRICE , TTQTY_SALEPRICE , TTIBCANCELQTY , TTADJQTY , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY , DCKEY , CHITYMD , SUBULYMD , ICGRTYPE , TRUNC_COSTPRICE , DIFF_TTQTY , DIFF_TTQTY_COSTPRICE ) SELECT 'IV' , TO_CHAR(TO_DATE(#{subulymd}, 'YYYYMMDD')-1, 'YYYYMMDD')||'150000' , A.CTKEY , A.OWKEY , A.ICKEY , A.LOGGRPCD , A.ICGRKEY , '' , 0 AS CARRYOVER_QTY , 0 AS CARRYOVER_COSTPRICE , 0 AS CARRYOVER_SALEPRICE , CLOSING_INVQTY , CLOSING_SALEPRICE , CLOSING_COSTPRICE , '70' , 0 , 0 , 0 , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , '' , '' , #{subulymd} , 'CATEGORY' AS ICGRTYPE , 0 , 0 , 0 FROM ( SELECT A.CTKEY , A.OWKEY , A.LOGGRPCD , A.TA_HDKEY , A.ICKEY , A.ICGRKEY , COALESCE(SUM(A.INVNQTY), 0) - COALESCE(SUM(A.CLOSING_INVQTY), 0) AS CLOSING_INVQTY , TRUNC(SUM(COALESCE(A.INVNQTY, 0) * COALESCE(C.AVGCOSTPRICE, B.COSTPRICE))) - TRUNC(SUM(A.CLOSING_INVQTY * COALESCE(C.AVGCOSTPRICE, B.COSTPRICE))) AS CLOSING_SALEPRICE , TRUNC(SUM(COALESCE(A.INVNQTY, 0) * B.COSTPRICE)) - TRUNC(SUM(A.CLOSING_INVQTY * B.COSTPRICE)) AS CLOSING_COSTPRICE FROM ( SELECT A.CTKEY , A.OWKEY , A.TA_HDKEY , A.LOGGRPCD , A.ICKEY , A.ICGRKEY , A.CLOSING_INVQTY , A.CLOSING_COSTPRICE , 0 AS INVNQTY FROM TWORK_INFO_PYSC_IVST A WHERE CRE_DATE BETWEEN TO_CHAR(TO_DATE(#{subulymd}, 'YYYYMMDD') - 1, 'YYYYMMDD') || '150000' AND #{subulymd} || '145959' AND TA_HDKEY NOT LIKE 'BACK%' AND A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey}
UNION ALL
SELECT A.CTKEY , A.OWKEY , B.TA_HDKEY , A.LOGGRPCD , C.ICKEY , C.ICGRKEY , 0 AS CLOSING_INVQTY , 0 AS CLOSING_COSTPRICE , SUM(A.QTY) AS INVNQTY FROM TWORK_INFO_TA_DT A INNER JOIN TWORK_INFO_TA_HD B ON A.TA_HDKEY = B.TA_HDKEY AND A.CTKEY = B.CTKEY INNER JOIN TWORK_MST_PYSC_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND A.TA_DTTYPE ='70' AND B.CYCLETYP = '10' AND A.WKSTATUS = '91' AND B.CYCLEFR BETWEEN TO_CHAR(TO_DATE(#{subulymd}, 'YYYYMMDD') - 1, 'YYYYMMDD') || '150000' AND #{subulymd} || '145959' AND C.CRE_DATE BETWEEN TO_CHAR(TO_DATE(#{subulymd}, 'YYYYMMDD') - 1, 'YYYYMMDD') || '150000' AND #{subulymd} || '145959' GROUP BY C.ICKEY , C.ICNAME , C.ICGRKEY , A.CTKEY , B.TA_HDKEY , A.OWKEY , A.LOGGRPCD ) A INNER JOIN TWORK_MST_PYSC_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY LEFT OUTER JOIN TWORK_MST_PYSC_AVGCOST C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY AND A.ICGRKEY = C.ICGRKEY AND A.TA_HDKEY = C.TA_HDKEY INNER JOIN TWORK_INFO_TA_HD D ON A.CTKEY = D.CTKEY AND A.TA_HDKEY = D.TA_HDKEY WHERE D.CTKEY = #{ctkey} AND D.OWKEY = #{owkey} AND B.CRE_DATE BETWEEN TO_CHAR(TO_DATE(#{subulymd}, 'YYYYMMDD') - 1, 'YYYYMMDD') || '150000' AND #{subulymd} || '145959' AND D.WKSTATUS = '91' GROUP BY A.CTKEY , A.LOGGRPCD , A.TA_HDKEY , A.ICKEY , A.ICGRKEY , A.OWKEY ) A

/* wms-report-icReceiptSearch-sql-oracle.xml - insertIcReceiptIvClose */ INSERT INTO TWORK_INFO_IVST1 ( CLOSING_TYPE /* 마감 유형 */ , CLOSING_DATE /* 마감 일자 */ , CTKEY /* 센터 코드 */ , OWKEY /* 화주 코드 */ , ICKEY /* 물품 코드 */ , LOGGRPCD /* 상저온 코드 */ , ICGRKEY /* 상품 그룹 코드 */ , STORE_KEY /* 점포 코드 */ , CARRYOVER_QTY /* 전일 재고 */ , CARRYOVER_COSTPRICE /* 전일 재고 원가 */ , CARRYOVER_SALEPRICE /* 전일 재고 총 판매가 */ , CLOSING_INVQTY /* 마감 재고 수량 */ , CLOSING_COSTPRICE /* 마감 재고 원가 */ , CLOSING_SALEPRICE /* 마감 재고 판매가 */ , ORHDTYPE /* 주문 공통 유형 */ , TTQTY /* 총 주문 원가 */ , TTQTY_COSTPRICE /* 총 주문 판매가 */ , TTQTY_SALEPRICE /* 총 입고 취소 수량 */ , TTIBCANCELQTY /* 총 조정 수량 */ , TTADJQTY , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY , DCKEY , CHITYMD , SUBULYMD , ICGRTYPE , TRUNC_COSTPRICE , DIFF_TTQTY , DIFF_TTQTY_COSTPRICE ) SELECT TO1.CLOSING_TYPE /* 마감 유형 */ , #{subulymd} || '000000' /* 마감 유형 */ , TO1.CTKEY /* 센터 코드 */ , TO1.OWKEY /* 화주 코드 */ , TO1.ICKEY /* 물품 코드 */ , TO1.LOGGRPCD /* 상저온 코드 */ , TO1.ICGRKEY /* 상품 그룹 코드 */ , '' , TO1.CARRYOVER_QTY , TO1.CARRYOVER_COSTPRICE , 0 , TO1.CARRYOVER_QTY + TO1.IBTT_QTY - TO1.OBTT_QTY + TO1.IV_CON_QTY AS CLOSING_IVQTY , TO1.CARRYOVER_COSTPRICE + TO1.IBTT_COSTPRICE - OBTT_COSTPRICE + TO1.IV_CON_COSTPRICE AS CLOSING_COSTPRICE , 0 , 'UNK' , 0 , 0 , 0 , 0 , 0 , #{sysdate} , #{surkey} , #{sysdate} , #{surkey} , '1' , '' , #{subulymd} , TO1.ICGRTYPE , 0 , 0 , 0 FROM ( SELECT 'IV' AS CLOSING_TYPE /* 마감 유형 */ , TO1.CTKEY /* 센터 코드 */ , TO1.OWKEY /* 화주 코드 */ , TO1.ICKEY /* 물품 코드 */ , TO1.LOGGRPCD /* 상저온 코드 */ , TO1.ICGRKEY /* 상품 그룹 코드 */ , TO1.ICGRTYPE , TO1.EX_DATE , COALESCE(( SELECT SUM(CLOSING_INVQTY) FROM TWORK_INFO_IVST1 A WHERE CLOSING_TYPE = 'IV' AND CTKEY = TO1.CTKEY AND OWKEY = TO1.OWKEY AND ICKEY = TO1.ICKEY AND CLOSING_DATE = TO1.EX_DATE), 0) AS CARRYOVER_QTY , COALESCE(( SELECT SUM(CLOSING_COSTPRICE) FROM TWORK_INFO_IVST1 A WHERE CLOSING_TYPE = 'IV' AND CTKEY = TO1.CTKEY AND OWKEY = TO1.OWKEY AND ICKEY = TO1.ICKEY AND CLOSING_DATE = TO1.EX_DATE), 0) AS CARRYOVER_COSTPRICE , SUM(TO1.IBTT_QTY) AS IBTT_QTY , SUM(TO1.OBTT_QTY) AS OBTT_QTY , SUM(TO1.IV_CON_QTY) AS IV_CON_QTY , SUM(TO1.IBTT_COSTPRICE) AS IBTT_COSTPRICE , SUM(OBTT_COSTPRICE) AS OBTT_COSTPRICE , SUM(TO1.IV_CON_COSTPRICE) AS IV_CON_COSTPRICE FROM ( SELECT TT1.CLOSING_TYPE /* 마감 유형 */ , TT1.CLOSING_DATE /* 마감 일자 */ , TT1.CTKEY /* 센터 코드 */ , TT1.OWKEY /* 화주 코드 */ , TT1.ICKEY /* 물품 코드 */ , TT1.LOGGRPCD /* 상저온 코드 */ , TT1.ICGRKEY /* 상품 그룹 코드 */ , TT1.ICGRTYPE , ( SELECT MAX(B.CLOSING_DATE) FROM TWORK_INFO_IVST1 B WHERE B.CTKEY = TT1.CTKEY AND B.OWKEY = TT1.OWKEY AND B.ICKEY = TT1.ICKEY AND B.CLOSING_TYPE = 'IV' AND B.CLOSING_DATE < TT1.CLOSING_DATE ) AS EX_DATE , TT1.CARRYOVER_QTY , TT1.CARRYOVER_COSTPRICE , TT1.IBTT_QTY , TT1.IBTT_COSTPRICE , TT1.OBTT_QTY , TRUNC(TT1.OBTT_QTY) AS OBTT_COSTPRICE /* 출고 금액 */ , TT1.IV_CON_QTY , TT1.IV_CON_COSTPRICE FROM ( SELECT TT1.CLOSING_TYPE /* 마감 유형 */ , TT1.CLOSING_DATE /* 마감 일자 */ , TT1.CTKEY /* 센터 코드 */ , TT1.OWKEY /* 화주 코드 */ , TT1.ICKEY /* 물품 코드 */ , TT1.LOGGRPCD /* 상저온 코드 */ , TT1.ICGRKEY /* 상품 그룹 코드 */ , TT1.ICGRTYPE , 0 AS CARRYOVER_QTY , 0 AS CARRYOVER_COSTPRICE , (TT1.ACIB_QTY + TT1.OI_QTY) - TT1.ACOB_QTY AS IBTT_QTY , TT1.ACIB_COSTPRICE + TT1.OI_COSTPRICE - TT1.ACOB_COSTPRICE AS IBTT_COSTPRICE , (TT1.STOB_QTY - TT1.STRI_QTY + TT1.SCO_QTY + TT1.OO_QTY + TT1.DUOB_QTY + TT1.DNOB_QTY + TT1.DPOB_QTY + (TT1.IC_REPLACE_QTY * -1)) AS OBTT_QTY , TT1.IV_CON_QTY , TT1.IV_CON_COSTPRICE FROM ( SELECT A.CLOSING_TYPE /* 마감 유형 */ , A.CLOSING_DATE /* 마감 일자 */ , A.CTKEY /* 센터 코드 */ , A.OWKEY /* 화주 코드 */ , A.ICKEY /* 물품 코드 */ , A.LOGGRPCD /* 상저온 코드 */ , A.ICGRKEY /* 상품 그룹 코드 */ , A.ICGRTYPE , A.STORE_KEY , CASE WHEN A.CLOSING_TYPE = 'IB' AND (A.ORHDTYPE = '10' OR A.ORHDTYPE = '100' OR A.ORHDTYPE = '200') THEN A.TTQTY ELSE 0 END AS ACIB_QTY /* 거래처 입고 수량 */ , CASE WHEN A.CLOSING_TYPE = 'IB' AND (A.ORHDTYPE = '10' OR A.ORHDTYPE = '100' OR A.ORHDTYPE = '200') THEN A.TTQTY_COSTPRICE ELSE 0 END AS ACIB_COSTPRICE /* 거래처 입고 금액 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '40' OR A.ORHDTYPE = '90' THEN A.TTQTY ELSE 0 END AS ACOB_QTY /* 거래처 반출 수량 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '40' OR A.ORHDTYPE = '90' THEN A.TTQTY_COSTPRICE ELSE 0 END AS ACOB_COSTPRICE /* 거래처 반출 금액 */ , CASE WHEN A.CLOSING_TYPE = 'IB' AND (A.ORHDTYPE = '60' OR A.ORHDTYPE = '90' OR A.ORHDTYPE = '180' OR A.ORHDTYPE = '120') THEN A.TTQTY ELSE 0 END AS OI_QTY /* 기타 입고 수량 */ , CASE WHEN A.CLOSING_TYPE = 'IB' AND (A.ORHDTYPE = '60' OR A.ORHDTYPE = '90' OR A.ORHDTYPE = '180' OR A.ORHDTYPE = '120') THEN A.TTQTY_COSTPRICE ELSE 0 END AS OI_COSTPRICE /* 기타 입고 금액 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND (A.ORHDTYPE = '10' OR A.ORHDTYPE = '20' OR A.ORHDTYPE = '30' OR A.ORHDTYPE = '60' OR A.ORHDTYPE = '70' OR A.ORHDTYPE = '910' OR ORHDTYPE = '200' OR A.ORHDTYPE = '300' OR A.ORHDTYPE = '310') THEN A.TTQTY ELSE 0 END AS STOB_QTY /* 점포 출고 수량 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND (A.ORHDTYPE = '10' OR A.ORHDTYPE = '20' OR A.ORHDTYPE = '30' OR A.ORHDTYPE = '60' OR A.ORHDTYPE = '70' OR A.ORHDTYPE = '910' OR ORHDTYPE = '200' OR A.ORHDTYPE = '300' OR A.ORHDTYPE = '310') THEN A.TTQTY_COSTPRICE ELSE 0 END AS STOB_COSTPRICE /* 점포 출고 금액 */ , CASE WHEN A.CLOSING_TYPE = 'IB' AND (A.ORHDTYPE = '50' OR A.ORHDTYPE = '950' OR A.ORHDTYPE = '190') THEN A.TTQTY ELSE 0 END AS STRI_QTY /* 점포 반입 수량 */ , CASE WHEN A.CLOSING_TYPE = 'IB' AND (A.ORHDTYPE = '50' OR A.ORHDTYPE = '950' OR A.ORHDTYPE = '190') THEN A.TTQTY_COSTPRICE ELSE 0 END AS STRI_COSTPRICE /* 점포 반입 금액 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND (A.ORHDTYPE = '10' OR A.ORHDTYPE = '20' OR A.ORHDTYPE = '30' OR A.ORHDTYPE = '40' OR A.ORHDTYPE = '50' OR A.ORHDTYPE = '60' OR A.ORHDTYPE = '70' OR A.ORHDTYPE = '910' OR A.ORHDTYPE = '200') THEN A.TTQTY_SALEPRICE ELSE 0 END AS STOB_SALEPRICE /* 점포 출고 매가 */ , CASE WHEN A.CLOSING_TYPE = 'IB' AND (A.ORHDTYPE = '50' OR A.ORHDTYPE = '950') THEN A.TTQTY_SALEPRICE ELSE 0 END AS STRI_SALEPRICE /* 점포 반입 매가 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '120' THEN A.TTQTY ELSE 0 END AS DUOB_QTY /* 폐기 수량 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '120' THEN A.TTQTY_COSTPRICE ELSE 0 END AS DUOB_COSTPRICE /* 폐기 금액 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '120' THEN A.TTQTY_SALEPRICE ELSE 0 END AS DUOB_SALEPRICE /* 폐기 매가 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '110' THEN A.TTQTY ELSE 0 END AS DNOB_QTY /* 기부 수량 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '110' THEN A.TTQTY_COSTPRICE ELSE 0 END AS DNOB_COSTPRICE /* 기부 금액 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '110' THEN A.TTQTY_SALEPRICE ELSE 0 END AS DNOB_SALEPRICE /* 기부 매가 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '130' THEN A.TTQTY ELSE 0 END AS DPOB_QTY /* 매각 수량 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '130' THEN A.TTQTY_COSTPRICE ELSE 0 END AS DPOB_COSTPRICE /* 매각 금액 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND (A.ORHDTYPE = '80' OR A.ORHDTYPE = '100' OR A.ORHDTYPE = '140' OR A.ORHDTYPE = '180' OR A.ORHDTYPE = '50') THEN A.TTQTY ELSE 0 END AS OO_QTY /* 기타 출고 수량 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND (A.ORHDTYPE = '80' OR A.ORHDTYPE = '100' OR A.ORHDTYPE = '140' OR A.ORHDTYPE = '180' OR A.ORHDTYPE = '50') THEN A.TTQTY_COSTPRICE ELSE 0 END AS OO_COSTPRICE /* 기타 출고 금액 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '190' THEN A.TTQTY ELSE 0 END AS SCO_QTY /* 자가 소비 수량 */ , CASE WHEN A.CLOSING_TYPE = 'OB' AND A.ORHDTYPE = '190' THEN A.TTQTY_COSTPRICE ELSE 0 END AS SCO_COSTPRICE /* 자가 소비 금액 */ , CASE WHEN A.CLOSING_TYPE = 'IV' AND (A.ORHDTYPE = '018' OR A.ORHDTYPE = '019') THEN A.CLOSING_INVQTY ELSE 0 END AS IC_REPLACE_QTY /* 상품 대체 수량 */ , CASE WHEN A.CLOSING_TYPE = 'IV' AND (A.ORHDTYPE = '018' OR A.ORHDTYPE = '019') THEN A.CLOSING_COSTPRICE ELSE 0 END AS IC_REPLACE_COSTPRICE /* 상품 대체 금액 */ , CASE WHEN A.CLOSING_TYPE = 'IV' AND A.ORHDTYPE = '70' THEN A.CLOSING_INVQTY ELSE 0 END AS IV_CON_QTY /* 재고 반영 수량 */ , CASE WHEN A.CLOSING_TYPE = 'IV' AND A.ORHDTYPE = '70' THEN A.CLOSING_COSTPRICE ELSE 0 END AS IV_CON_COSTPRICE /* 재고 반영 금액 */ , A.TRUNC_COSTPRICE /* 원가 정산 금액 */ , A.DCKEY FROM TWORK_INFO_IVST1 A WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND A.CLOSING_DATE = #{subulymd}|| '000000' ) TT1
UNION ALL
SELECT TT2.CLOSING_TYPE /* 마감 유형 */ , TT2.CLOSING_DATE /* 마감 일자 */ , TT2.CTKEY /* 센터 코드 */ , TT2.OWKEY /* 화주 코드 */ , TT2.ICKEY /* 물품 코드 */ , TT2.LOGGRPCD /* 상저온 코드 */ , TT2.ICGRKEY /* 상품 그룹 코드 */ , TT2.ICGRTYPE , TT2.CLOSING_INVQTY AS CARRYOVER_QTY , TT2.CLOSING_COSTPRICE AS CARRYOVER_COSTPRICE , 0 AS IBTT_QTY , 0 AS IBTT_COSTPRICE , 0 AS OBTT_QTY , 0 AS IV_CON_QTY , 0 AS IV_CON_COSTPRICE FROM TWORK_INFO_IVST1 TT2 WHERE TT2.CLOSING_TYPE = 'IV' AND TT2.CLOSING_DATE = #{subulymd}|| '150000' AND TT2.CTKEY = #{ctkey} AND TT2.OWKEY = #{owkey} AND TT2.ORHDTYPE = 'UNK' ) TT1 ) TO1 GROUP BY TO1.CTKEY /* 센터 코드 */ , TO1.OWKEY /* 화주 코드 */ , TO1.ICKEY /* 물품 코드 */ , TO1.LOGGRPCD /* 상저온 코드 */ , TO1.ICGRKEY /* 상품 그룹 코드 */ , TO1.ICGRTYPE , TO1.EX_DATE ) TO1

